katter = {"Lusse": 3 , "Smulan": 8}
print(katter["Lusse"]) # Ger oss värdet 3

#Från nycklarna kommer vi åt värdena
for nyckel in katter.keys():
	print(nyckel, "har värdet", katter[nyckel])

#Men inte åt andra hållet, här ett exempel på att skriva ut värdena	
for värdet in katter.values():
  print(värdet)

#.items ger både nycklar och värden
for nyckel, värdet in katter.items():
  print(nyckel, "har värdet", värdet)
